INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"triangle"', '"Prsnt"', '"vanilla"', '{"demo.css": ".triangle {\n  width: 0;\n  height: 0;\n  border-top: 20px solid #9C27B0;\n  border-left: 20px solid transparent;\n  border-right: 20px solid transparent;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Triangle\r\n    </h1>\r\n    <div class=\"triangle\"></div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/triangle"}'), ('"triangle-buttons"', '"Prsnt"', '"vanilla"', '{"demo.css": ".triangle-buttons {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Spacing */\n  padding: 0.5rem;\n}\n\n.triangle-buttons__triangle {\n  border-style: solid;\n\n  /* Size */\n  height: 0px;\n  width: 0px;\n}\n\n.triangle-buttons__triangle--t {\n  border-color: transparent transparent #d1d5db;\n  border-width: 0 0.5rem 0.5rem;\n}\n\n.triangle-buttons__triangle--r {\n  border-color: transparent transparent transparent #d1d5db;\n  border-width: 0.5rem 0 0.5rem 0.5rem;\n}\n\n.triangle-buttons__triangle--b {\n  border-color: #d1d5db transparent transparent;\n  border-width: 0.5rem 0.5rem 0;\n}\n\n.triangle-buttons__triangle--l {\n  border-color: transparent #d1d5db transparent transparent;\n  border-width: 0.5rem 0.5rem 0.5rem 0;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Triangle Buttons\r\n    </h1>\r\n    <!-- Up triangle button -->\r\n    <button class=\"triangle-buttons\">\r\n      <!-- Triangle -->\r\n      <div\r\n        class=\"triangle-buttons__triangle triangle-buttons__triangle--t\"\r\n      ></div>\r\n\r\n      <!-- Content -->\r\n      Content\r\n    </button>\r\n\r\n    <!-- Right triangle button -->\r\n    <button class=\"triangle-buttons\">\r\n      <!-- Content -->\r\n      Content\r\n\r\n      <!-- Triangle -->\r\n      <div\r\n        class=\"triangle-buttons__triangle triangle-buttons__triangle--r\"\r\n      ></div>\r\n    </button>\r\n\r\n    <!-- Down triangle button -->\r\n    <button class=\"triangle-buttons\">\r\n      <!-- Triangle -->\r\n      <div\r\n        class=\"triangle-buttons__triangle triangle-buttons__triangle--b\"\r\n      ></div>\r\n\r\n      <!-- Content -->\r\n      Content\r\n    </button>\r\n\r\n    <!-- Left triangle button -->\r\n    <button class=\"triangle-buttons\">\r\n      <!-- Triangle -->\r\n      <div\r\n        class=\"triangle-buttons__triangle triangle-buttons__triangle--l\"\r\n      ></div>\r\n\r\n      <!-- Content -->\r\n      Content\r\n    </button>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/triangle-buttons"}'), ('"video-background"', '"Prsnt"', '"vanilla"', '{"demo.css": ".video-background {\n  /* Used to position the video and content */\n  position: relative;\n}\n\n.video-background__inner {\n  /* Positioned at the top left corner */\n  left: 0px;\n  position: absolute;\n  top: 0px;\n\n  /* Take full size */\n  height: 100%;\n  width: 100%;\n\n  /* Hide the scrollbar */\n  overflow: hidden;\n}\n\n.video-background__video {\n  object-fit: cover;\n\n  /* Take full width */\n  height: 100%;\n  max-width: 100%;\n}\n\n.video-background__content {\n  /* Positioned at the top left corner */\n  left: 0px;\n  position: absolute;\n  top: 0px;\n\n  /* Take full size */\n  height: 100%;\n  width: 100%;\n\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Video Background\r\n    </h1>\r\n    <div class=\"video-background\">\r\n      <!-- The video container -->\r\n      <div class=\"video-background__inner\">\r\n        <video class=\"video-background__video\" src=\"...\">container</video>\r\n      </div>\r\n\r\n      <!-- The content -->\r\n      <div class=\"video-background__content\">Content</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/video-background"}'), ('"voting"', '"Prsnt"', '"vanilla"', '{"demo.css": ".voting {\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n  display: flex;\n  flex-direction: column;\n  height: 8rem;\n}\n\n.voting__button {\n  /* Reset */\n  background: none;\n  border: none;\n  cursor: pointer;\n\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Size */\n  height: 1rem;\n\n  /* Position the triangle */\n  position: relative;\n}\n\n.voting__triangle {\n  border-style: solid;\n\n  /* Size */\n  height: 0;\n  width: 0;\n}\n\n.voting__triangle--up {\n  border-color: transparent transparent #d1d5db;\n  border-width: 0 0.5rem 0.5rem;\n}\n\n.voting__triangle--down {\n  border-color: #d1d5db transparent transparent;\n  border-width: 0.5rem 0.5rem 0px;\n}\n\n.voting__number {\n  /* Take the available height */\n  flex: 1;\n\n  /* Center the number */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Spacing */\n  padding: 0.25rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div class=\"voting\">\r\n      <!-- Up button -->\r\n      <button class=\"voting__button\">\r\n        <div class=\"voting__triangle voting__triangle--up\"></div>\r\n      </button>\r\n\r\n      <!-- Number -->\r\n      <div class=\"voting__number\">Number</div>\r\n\r\n      <!-- Down button -->\r\n      <button class=\"voting__button\">\r\n        <div class=\"voting__triangle voting__triangle--down\"></div>\r\n      </button>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/voting"}'), ('"watermark"', '"Prsnt"', '"vanilla"', '{"demo.css": ".watermark {\n  /* Used to position the watermark */\n  position: relative;\n}\n\n.watermark__inner {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Absolute position */\n  left: 0px;\n  position: absolute;\n  top: 0px;\n\n  /* Take full size */\n  height: 100%;\n  width: 100%;\n}\n\n.watermark__body {\n  /* Text color */\n  color: rgba(0, 0, 0, 0.2);\n\n  /* Text styles */\n  font-size: 3rem;\n  font-weight: bold;\n  text-transform: uppercase;\n\n  /* Rotate the text */\n  transform: rotate(-45deg);\n\n  /* Disable the selection */\n  user-select: none;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Watermark\r\n    </h1>\r\n    <div class=\"watermark\">\r\n      <!-- Watermark container -->\r\n      <div class=\"watermark__inner\">\r\n        <!-- The watermark -->\r\n        <div class=\"watermark__body\">Draft</div>\r\n      </div>\r\n\r\n      <!-- Other content -->\r\n      Other Content\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/watermark"}'), ('"zigzag-timeline"', '"Prsnt"', '"vanilla"', '{"demo.css": ".zigzag-timeline__item {\n  /* Used to position the milestone */\n  position: relative;\n\n  /* Border */\n  border-bottom: 1px solid #9ca3af;\n\n  /* Take full width */\n  width: 100%;\n}\n\n.zigzag-timeline__milestone {\n  /* Absolute position */\n  position: absolute;\n  top: 50%;\n\n  /* Circle it */\n  border-radius: 50%;\n  height: 1rem;\n  width: 1rem;\n\n  /* Misc */\n  background: #9ca3af;\n}\n\n/* Styles for even items */\n.zigzag-timeline__item:nth-child(2n) {\n  border-left: 1px solid #9ca3af;\n}\n.zigzag-timeline__item:nth-child(2n) .zigzag-timeline__milestone {\n  left: 0;\n  transform: translate(-50%, -50%);\n}\n\n/* Styles for odd items */\n.zigzag-timeline__item:nth-child(2n + 1) {\n  border-right: 1px solid #9ca3af;\n}\n.zigzag-timeline__item:nth-child(2n + 1) .zigzag-timeline__milestone {\n  right: 0;\n  transform: translate(50%, -50%);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Zigzag Timeline\r\n    </h1>\r\n    <div class=\"zigzag-timeline__item\">\r\n      <!-- Milestone -->\r\n      <div className=\"zigzag-timeline__milestone\">Milestone</div>\r\n\r\n      <!-- Content -->\r\n      Content\r\n    </div>\r\n\r\n    <!-- Repeat other items -->\r\n    Repeat Other items\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Display/zigzag-timeline"}'), ('"25-css-gradients-for-your-next-project"', '"Prsnt"', '"vanilla"', '{"demo.css": ".gradient-box {\n  width: 100%;\n  height: 64px;\n  border-radius: 8px 8px 0 0;\n  margin-bottom: -16px;\n  margin-top: 32px;\n}\n\n.stripe {\n  background: linear-gradient(to right, #1fa2ff, #12d8fa, #a6ffcb);\n}\n\n.flare {\n  background: linear-gradient(to right, #f12711, #f5af19);\n}\n\n.vanusa {\n  background: linear-gradient(to right, #da4453, #89216b);\n}\n\n.sublime-light {\n  background: linear-gradient(to right, #fc5c7d, #6a82fb);\n}\n\n.bighead {\n  background: linear-gradient(to right, #c94b4b, #4b134f);\n}\n\n.velvet-sun {\n  background: linear-gradient(to right, #e1eec3, #f05053);\n}\n\n.argon {\n  background: linear-gradient(to right, #03001e, #7303c0, #ec38bc, #fdeff9);\n}\n\n.celestial {\n  background: linear-gradient(to right, #c33764, #1d2671);\n}\n\n.relay {\n  background: linear-gradient(to right, #3a1c71, #d76d77, #ffaf7b);\n}\n\n.crystal-clear {\n  background: linear-gradient(to right, #159957, #155799);\n}\n\n.ibiza-sunset {\n  background: linear-gradient(to right, #ee0979, #ff6a00);\n}\n\n.fresh-turboscent {\n  background: linear-gradient(to right, #f1f2b5, #135058);\n}\n\n.cheer-up-emo-kid {\n  background: linear-gradient(to right, #556270, #ff6b6b);\n}\n\n.starfall {\n  background: linear-gradient(to right, #f0c27b, #4b1248);\n}\n\n.nelson {\n  background: linear-gradient(to right, #f2709c, #ff9472);\n}\n\n.forever-lost {\n  background: linear-gradient(to right, #5d4157, #a8caba);\n}\n\n.blurry-beach {\n  background: linear-gradient(to right, #d53369, #cbad6d);\n}\n\n.influenza {\n  background: linear-gradient(to right, #c04848, #480048);\n}\n\n.jshine {\n  background: linear-gradient(to right, #12c2e9, #c471ed, #f64f59);\n}\n\n.calm-darya {\n  background: linear-gradient(to right, #5f2c82, #49a09d);\n}\n\n.titanium {\n  background: linear-gradient(to right, #283048, #859398);\n}\n\n.pinky {\n  background: linear-gradient(to right, #dd5e89, #f7bb97);\n}\n\n.purple-paradise {\n  background: linear-gradient(to right, #1d2b64, #f8cdda);\n}\n\n.horizon {\n  background: linear-gradient(to right, #003973, #e5e5be);\n}\n\n.noon-to-dusk {\n  background: linear-gradient(to right, #ff6e7f, #bfe9ff);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      25 CSS gradients for your next project\r\n    </h1>\r\n    <div class=\"gradient-box stripe\"></div>\r\n    <div class=\"gradient-box flare\"></div>\r\n    <div class=\"gradient-box vanusa\"></div>\r\n    <div class=\"gradient-box sublime-light\"></div>\r\n    <div class=\"gradient-box bighead\"></div>\r\n    <div class=\"gradient-box velvet-sun\"></div>\r\n    <div class=\"gradient-box argon\"></div>\r\n    <div class=\"gradient-box celestial\"></div>\r\n    <div class=\"gradient-box relay\"></div>\r\n    <div class=\"gradient-box crystal-clear\"></div>\r\n    <div class=\"gradient-box ibiza-sunset\"></div>\r\n    <div class=\"gradient-box fresh-turboscent\"></div>\r\n    <div class=\"gradient-box cheer-up-emo-kid\"></div>\r\n    <div class=\"gradient-box starfall\"></div>\r\n    <div class=\"gradient-box nelson\"></div>\r\n    <div class=\"gradient-box forever-lost\"></div>\r\n    <div class=\"gradient-box blurry-beach\"></div>\r\n    <div class=\"gradient-box influenza\"></div>\r\n    <div class=\"gradient-box jshine\"></div>\r\n    <div class=\"gradient-box calm-darya\"></div>\r\n    <div class=\"gradient-box titanium\"></div>\r\n    <div class=\"gradient-box pinky\"></div>\r\n    <div class=\"gradient-box purple-paradise\"></div>\r\n    <div class=\"gradient-box horizon\"></div>\r\n    <div class=\"gradient-box noon-to-dusk\"></div>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Effect/25-css-gradients-for-your-next-project"}'), ('"border-with-top-triangle"', '"Prsnt"', '"vanilla"', '{"demo.css": ".container {\n  position: relative;\n  background: #ffffff;\n  padding: 15px;\n  border: 1px solid #dddddd;\n  margin-top: 20px;\n}\n\n.container::before,\n.container::after {\n  content: '''';\n  position: absolute;\n  bottom: 100%;\n  left: 19px;\n  border: 11px solid transparent;\n  border-bottom-color: #dddddd;\n}\n\n.container::after {\n  left: 20px;\n  border: 10px solid transparent;\n  border-bottom-color: #ffffff;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Border with top triangle\r\n    </h1>\r\n    <div class=\"container\">Border with top triangle</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Effect/border-with-top-triangle"}'), ('"checkerboard-background-pattern"', '"Prsnt"', '"vanilla"', '{"demo.css": ".checkerboard {\n  width: 240px;\n  height: 240px;\n  background-color: #fff;\n  background-image: linear-gradient(\n     